630: func isSampleOld(baseTime time.Time, sampleAgeLimit time.Duration, ts int64) bool {
631: 	if sampleAgeLimit == 0 {
632: 		// If sampleAgeLimit is unset, then we never skip samples due to their age.
633: 		return false
634: 	}
635: 	limitTs := baseTime.Add(-sampleAgeLimit)
636: 	sampleTs := timestamp.Time(ts)
637: 	return sampleTs.Before(limitTs)
