1013: // SeriesReset is used when reading a checkpoint. WAL Watcher should have
1014: // stored series records with the checkpoints index number, so we can now
1015: // delete any ref ID's lower than that # from the two maps.
1016: func (t *QueueManager) SeriesReset(index int) {
1017: 	t.seriesMtx.Lock()
1018: 	defer t.seriesMtx.Unlock()
1019: 	t.seriesSegmentMtx.Lock()
1020: 	defer t.seriesSegmentMtx.Unlock()
1021: 	// Check for series that are in segments older than the checkpoint
1022: 	// that were not also present in the checkpoint.
1023: 	for k, v := range t.seriesSegmentIndexes {
1024: 		if v < index {
1025: 			delete(t.seriesSegmentIndexes, k)
1026: 			delete(t.seriesLabels, k)
1027: 			delete(t.seriesMetadata, k)
1028: 			delete(t.droppedSeries, k)
1029: 		}
1030: 	}
1031: }
